 28	import useNetworkPolicyColumn from './hooks/useNetworkPolicyColumn';
 29	
 30	import '@styles/list-management-group.scss';
 31	
 32	type MultiNetworkPolicyListProps = {
 33	  namespace: string;
 34	};
 35	
 36	const MultiNetworkPolicyList: FC<MultiNetworkPolicyListProps> = ({ namespace }) => {
 37	  const { t } = useNetworkingTranslation();
 38	  const navigate = useNavigate();
 39	
 40	  const [multinetworkPolicies, loaded, loadError] = useK8sWatchResource<
 41	    IoK8sApiNetworkingV1NetworkPolicy[]
 42	  >({
 43	    groupVersionKind: modelToGroupVersionKind(MultiNetworkPolicyModel),
 44	    isList: true,
 45	    namespace,
 46	  });
 47	
 48	  const { onPaginationChange, pagination } = usePagination();
 49	  const [data, filteredData, onFilterChange] = useListPageFilter(multinetworkPolicies);
 50	  const [columns, activeColumns] = useNetworkPolicyColumn(pagination, data);
 51	  const title = t('MultiNetworkPolicies');
 52	
 53	  return (
 54	    <ListEmptyState<IoK8sApiNetworkingV1NetworkPolicy>
 55	      createButtonlink={SHARED_DEFAULT_PATH_NEW_RESOURCE_FORM}
 56	      data={data}
 57	      kind={MultiNetworkPolicyModel.kind}
 58	      learnMoreLink="https://docs.openshift.com/dedicated/networking/network_policy/creating-network-policy.html"
 59	      loaded={loaded}
 60	      title={title}
 61	    >
 62	      <ListPageHeader title={title}>
 63	        {!isEmpty(data.length) && (
 64	          <ListPageCreateButton
 65	            className="list-page-create-button-margin"
 66	            createAccessReview={{
 67	              groupVersionKind: modelToGroupVersionKind(MultiNetworkPolicyModel),
 68	              namespace,
 69	            }}
 70	            onClick={() =>
 71	              navigate(
 72	                `${resourcePathFromModel(
 73	                  MultiNetworkPolicyModel,
 74	                  null,
 75	                  namespace || DEFAULT_NAMESPACE,
 76	                )}/${SHARED_DEFAULT_PATH_NEW_RESOURCE_FORM}`,
 77	              )
 78	            }
 79	          >
 80	            {t('Create MultiNetworkPolicy')}
 81	          </ListPageCreateButton>
 82	        )}
 83	      </ListPageHeader>
 84	      <ListPageBody>
 85	        <div className="list-management-group">
 86	          <ListPageFilter
 87	            columnLayout={{
 88	              columns: columns?.map(({ additional, id, title: columnTitle }) => ({
 89	                additional,
 90	                id,
 91	                title: columnTitle,
 92	              })),
 93	              id: MultiNetworkPolicyModel.kind,
 94	              selectedColumns: new Set(activeColumns?.map((col) => col?.id)),
 95	              type: '',
 96	            }}
 97	            data={data}
 98	            loaded={loaded}
 99	            onFilterChange={(...args) => {
100	              onFilterChange(...args);
101	              onPaginationChange({
102	                endIndex: pagination?.perPage,
103	                page: 1,
104	                perPage: pagination?.perPage,
105	                startIndex: 0,
106	              });
107	            }}
108	          />
109	          {loaded && !isEmpty(data.length) && (
110	            <Pagination
111	              isLastFullPageShown
112	              itemCount={data.length}
113	              onPerPageSelect={(_e, perPage, page, startIndex, endIndex) =>
114	                onPaginationChange({ endIndex, page, perPage, startIndex })
115	              }
116	              onSetPage={(_e, page, perPage, startIndex, endIndex) =>
117	                onPaginationChange({ endIndex, page, perPage, startIndex })
118	              }
119	              page={pagination?.page}
120	              perPage={pagination?.perPage}
121	              perPageOptions={paginationDefaultValues}
122	            />
123	          )}
124	        </div>
125	        <VirtualizedTable<IoK8sApiNetworkingV1NetworkPolicy>
126	          columns={activeColumns}
127	          data={filteredData}
128	          loaded={loaded}
129	          loadError={loadError}
130	          NoDataEmptyMsg={NetworkPolicyEmptyState}
131	          Row={NetworkPolicyRow}
132	          unfilteredData={data}
133	        />
134	      </ListPageBody>
135	    </ListEmptyState>
136	  );
137	};
138	
139	export default MultiNetworkPolicyList;

