 1	import React, { ReactNode } from 'react';
 2	import { Trans } from 'react-i18next';
 3	import { useNavigate, useParams } from 'react-router-dom-v5-compat';
 4	
 5	import { K8sResourceCommon, ListPageHeader } from '@openshift-console/dynamic-plugin-sdk';
 6	import {
 7	  Button,
 8	  ButtonVariant,
 9	  EmptyState,
10	  EmptyStateActions,
11	  EmptyStateBody,
12	  EmptyStateFooter,
13	} from '@patternfly/react-core';
14	import { AddCircleOIcon } from '@patternfly/react-icons';
15	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
16	import { isEmpty } from '@utils/utils';
17	
18	import ExternalLink from '../ExternalLink/ExternalLink';
19	import Loading from '../Loading/Loading';
20	
21	type ListEmptyStateProps<T> = {
22	  children: ReactNode;
23	  createButtonlink: string;
24	  data: T[];
25	  kind: string;
26	  learnMoreLink: string;
27	  loaded: boolean;
28	  title: string;
29	};
30	
31	const ListEmptyState = <T extends K8sResourceCommon>({
32	  children,
33	  createButtonlink,
34	  data,
35	  kind,
36	  learnMoreLink,
37	  loaded,
38	  title,
39	}: ListEmptyStateProps<T>) => {
40	  const { t } = useNetworkingTranslation();
41	  const navigate = useNavigate();
42	  const params = useParams();
43	  if (!loaded) return <Loading />;
44	
45	  if (isEmpty(data))
46	    return (
47	      <>
48	        <ListPageHeader title={title} />
49	        <EmptyState
50	          headingLevel="h4"
51	          icon={AddCircleOIcon}
52	          titleText={t('No {{kind}} found', { kind })}
53	        >
54	          <EmptyStateBody>
55	            <Trans t={t}>
56	              Click <b>Create {{ kind }}</b> to create your first {{ kind }}
57	            </Trans>
58	          </EmptyStateBody>
59	          <EmptyStateFooter>
60	            <EmptyStateActions>
61	              <Button
62	                onClick={() =>
63	                  navigate(
64	                    params?.ns
65	                      ? createButtonlink
66	                      : `/k8s/ns/default/${params.plural}/${createButtonlink}`,
67	                  )
68	                }
69	                variant={ButtonVariant.primary}
70	              >
71	                {t('Create {{ kind }}', { kind })}
72	              </Button>
73	            </EmptyStateActions>
74	            <EmptyStateActions>
75	              <ExternalLink href={learnMoreLink}>
76	                {t('Learn more about {{ kind }}', { kind })}
77	              </ExternalLink>
78	            </EmptyStateActions>
79	          </EmptyStateFooter>
80	        </EmptyState>
81	      </>
82	    );
83	
84	  return <>{children}</>;
85	};
86	
87	export default ListEmptyState;

